import{_ as a,o,c as r,a3 as t}from"./chunks/framework.aYYe0dfI.js";const g=JSON.parse('{"title":"Module generate","description":"generate 模块负责文档生成的完整流程，包括生成前验证、同步与异步页面构建以及结果输出。它对外提供四个核心函数：generate_dry_run 用于在无副作用的前提下模拟生成过程并返回状态或预估统计；generate_pages 是同步阻塞的入口，接收分析数据、输出路径、并发数及格式标识，在成功时保证输出目录中包含完整且引用一致的文档集；write_pages 将已生成的页面集合写入指定目录；generate_pages_async 则在给定的 kota::event_loop 上执行异步页面生成，调用者必须显式调度返回的任务以触发实际工作。模块内部管理配置、模型、速率限制、页面集合及输出根路径等状态，并依赖 config 模块提供配置数据、依赖 extract 模块提供预处理的符号与分析结果。","frontmatter":{"title":"Module generate","description":"generate 模块负责文档生成的完整流程，包括生成前验证、同步与异步页面构建以及结果输出。它对外提供四个核心函数：generate_dry_run 用于在无副作用的前提下模拟生成过程并返回状态或预估统计；generate_pages 是同步阻塞的入口，接收分析数据、输出路径、并发数及格式标识，在成功时保证输出目录中包含完整且引用一致的文档集；write_pages 将已生成的页面集合写入指定目录；generate_pages_async 则在给定的 kota::event_loop 上执行异步页面生成，调用者必须显式调度返回的任务以触发实际工作。模块内部管理配置、模型、速率限制、页面集合及输出根路径等状态，并依赖 config 模块提供配置数据、依赖 extract 模块提供预处理的符号与分析结果。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/generate/index.md","filePath":"zh/clore/modules/generate/index.md"}'),c={name:"zh/clore/modules/generate/index.md"};function d(n,e,s,i,l,p){return o(),r("div",null,[...e[0]||(e[0]=[t("",60)])])}const h=a(c,[["render",d]]);export{g as __pageData,h as default};
